def is_valid_bharat_mata_depiction(depiction):
    valid_features = {
        'red_sari', 'saffron_sari', 'holding_flag',
        'standing_on_lotus', 'accompanied_by_lion'
    }
    depiction_features = set(depiction.lower().split())
    return bool(valid_features & depiction_features)

# Example usage:
depiction = "Bharat Mata wearing a red sari and holding a flag"
print(is_valid_bharat_mata_depiction(depiction))  # Output: True
